const credentials = [
  'Google Gemini(PaLM) Api account 2', 
  'Google Gemini(PaLM) Api account'
];

const selectedKey = credentials[Math.floor(Math.random() * credentials.length)];

let userMessage = "";

try {
  const inputData = $("Webhook").item.json;
  userMessage = inputData.body.message || inputData.chatInput || "";
} catch (e) {
  try {
    userMessage = $("When chat message received").item.json.chatInput || "";
  } catch (e2) {
    userMessage = "Hello";
  }
}

userMessage = userMessage.trim();
if (userMessage === "") userMessage = "Hello";

return {
  selectedKey: selectedKey,
  chatInput: userMessage
};

const fullResponse = $node["AI Agent"].json.output;
const dataMarker = "###DATA###";
let cleanText = fullResponse;
let scenes = [];
let georgeData = {};

if (fullResponse.includes(dataMarker)) {
  const parts = fullResponse.split(dataMarker);
  cleanText = parts[0].trim();
  try {
    georgeData = JSON.parse(parts[1].trim());
    scenes = georgeData.video_scenes || [];
  } catch (e) {
    scenes = [{ scene: 1, voiceText: "George is ready!", videoPrompt: "Cinematic cooking shot" }];
  }
}

return scenes.map(scene => {
  return {
    json: {
      bellaResponse: cleanText,
      recipeName: georgeData.recipe_name || "Special Dish",
      videoPrompt: scene.videoPrompt, 
      voiceText: scene.voiceText,
      sceneNumber: scene.scene,
      georgeJson: georgeData
    }
  };
});
